<?php
require_once __DIR__.'/../includes/header.php';
require_once __DIR__.'/../config/database.php';
check_access([2]);$db=Database::getInstance();
$stmt=$db->prepare("SELECT u.id,u.nama_ujian,u.jenis_ujian,p.kelas_id,p.mapel_id,k.nama_kelas,m.nama_mapel
 FROM ujian u JOIN pengajaran p ON p.id=u.pengajaran_id JOIN guru g ON g.id=p.guru_id
 JOIN kelas k ON k.id=p.kelas_id JOIN mapel m ON m.id=p.mapel_id WHERE g.user_id=?
 ORDER BY k.nama_kelas,m.nama_mapel,u.nama_ujian");$stmt->execute([$_SESSION['user_id']]);$opsiUjian=$stmt->fetchAll();
$ujianId=(int)($_GET['ujian_id']??0);$sesiId=(int)($_GET['sesi_id']??0);$filterKelas=(int)($_GET['kelas_id']??0);$filterMapel=(int)($_GET['mapel_id']??0);
if($ujianId>0){foreach($opsiUjian as $o)if((int)$o['id']===$ujianId){if(!$filterKelas)$filterKelas=(int)$o['kelas_id'];if(!$filterMapel)$filterMapel=(int)$o['mapel_id'];break;}}
if(!$filterKelas&&$opsiUjian)$filterKelas=(int)$opsiUjian[0]['kelas_id'];
$mapelTersedia=array_values(array_filter($opsiUjian,static fn($o)=>(int)$o['kelas_id']===$filterKelas));
if(!$filterMapel&&$mapelTersedia)$filterMapel=(int)$mapelTersedia[0]['mapel_id'];
$ujianTersedia=array_values(array_filter($opsiUjian,static fn($o)=>(int)$o['kelas_id']===$filterKelas&&(int)$o['mapel_id']===$filterMapel));
if(!$ujianId||!array_filter($ujianTersedia,static fn($o)=>(int)$o['id']===$ujianId))$ujianId=(int)($ujianTersedia[0]['id']??0);
$stmt=$db->prepare("SELECT u.id,u.nama_ujian,u.jenis_ujian,u.durasi_menit,m.nama_mapel,k.nama_kelas,g.nama_lengkap nama_guru
 FROM ujian u JOIN pengajaran p ON p.id=u.pengajaran_id JOIN guru g ON g.id=p.guru_id
 JOIN mapel m ON m.id=p.mapel_id JOIN kelas k ON k.id=p.kelas_id
 WHERE u.id=? AND g.user_id=?");$stmt->execute([$ujianId,$_SESSION['user_id']]);$ujian=$stmt->fetch();
if(!$ujian){http_response_code(404);exit('Belum ada ujian pada kelas atau mata pelajaran ini.');}
$stmt=$db->prepare("SELECT su.id,su.waktu_mulai,su.waktu_selesai,su.status,s.id siswa_id,s.nisn,s.nama_lengkap,
 SUM(CASE WHEN js.id IS NOT NULL AND ((js.jawaban_pg IS NOT NULL) OR (js.jawaban_esai IS NOT NULL AND TRIM(js.jawaban_esai)<>'')) THEN 1 ELSE 0 END) jumlah_dijawab,(SELECT COUNT(*) FROM soal_ujian so WHERE so.ujian_id=su.ujian_id) total_soal,
 COALESCE(nu.nilai_pg,0) nilai_pg,COALESCE(nu.nilai_esai,0) nilai_esai,COALESCE(nu.nilai_total,0) nilai_total
 FROM sesi_ujian su JOIN siswa s ON s.id=su.siswa_id
 LEFT JOIN jawaban_siswa js ON js.sesi_ujian_id=su.id
 LEFT JOIN nilai_ujian nu ON nu.ujian_id=su.ujian_id AND nu.siswa_id=su.siswa_id
 WHERE su.ujian_id=? GROUP BY su.id ORDER BY su.status='Berlangsung' DESC,s.nama_lengkap");$stmt->execute([$ujianId]);$peserta=$stmt->fetchAll();
$detail=null;$jawaban=[];
if($sesiId>0){
 $stmt=$db->prepare("SELECT su.id,su.status,su.waktu_mulai,su.waktu_selesai,s.nisn,s.nama_lengkap
  FROM sesi_ujian su JOIN siswa s ON s.id=su.siswa_id WHERE su.id=? AND su.ujian_id=?");$stmt->execute([$sesiId,$ujianId]);$detail=$stmt->fetch();
 if(!$detail){http_response_code(404);exit('Sesi siswa tidak ditemukan.');}
 $stmt=$db->prepare("SELECT so.id,so.tipe_soal,so.pertanyaan,so.opsi_a,so.opsi_b,so.opsi_c,so.opsi_d,so.opsi_e,so.kunci_jawaban,so.bobot,
  js.jawaban_pg,js.jawaban_esai,js.is_benar,js.nilai_esai
  FROM soal_ujian so LEFT JOIN jawaban_siswa js ON js.soal_id=so.id AND js.sesi_ujian_id=?
  WHERE so.ujian_id=? ORDER BY so.id");$stmt->execute([$sesiId,$ujianId]);$jawaban=$stmt->fetchAll();
}
$selesai=count(array_filter($peserta,static fn($p)=>$p['status']==='Selesai'));$berlangsung=count($peserta)-$selesai;
?>
