<section class="card result-card mb-3"><div class="card-body p-3"><form method="get" id="resultFilterForm" class="row g-2 align-items-end"><div class="col-md-3"><label class="form-label small fw-semibold">Kelas</label><select class="form-select" name="kelas_id" id="hasilKelas"><?php $kelasSeen=[];foreach($opsiUjian as $o):if(isset($kelasSeen[$o['kelas_id']]))continue;$kelasSeen[$o['kelas_id']]=true; ?><option value="<?= (int)$o['kelas_id'] ?>" <?= $filterKelas===(int)$o['kelas_id']?'selected':'' ?>><?= sanitize($o['nama_kelas']) ?></option><?php endforeach ?></select></div><div class="col-md-3"><label class="form-label small fw-semibold">Mata Pelajaran</label><select class="form-select" name="mapel_id" id="hasilMapel"><?php $mapelSeen=[];foreach($mapelTersedia as $o):if(isset($mapelSeen[$o['mapel_id']]))continue;$mapelSeen[$o['mapel_id']]=true; ?><option value="<?= (int)$o['mapel_id'] ?>" <?= $filterMapel===(int)$o['mapel_id']?'selected':'' ?>><?= sanitize($o['nama_mapel']) ?></option><?php endforeach ?></select></div><div class="col-md-4"><label class="form-label small fw-semibold">Ujian / Kuis</label><select class="form-select" name="ujian_id" id="hasilUjian"><?php foreach($ujianTersedia as $o): ?><option value="<?= (int)$o['id'] ?>" <?= $ujianId===(int)$o['id']?'selected':'' ?>><?= sanitize($o['nama_ujian'].' ('.$o['jenis_ujian'].')') ?></option><?php endforeach ?></select></div><div class="col-md-2"><button class="btn btn-primary w-100"><i class="fa-solid fa-filter me-1"></i>Tampilkan</button></div></form></div></section>
<section class="card result-hero mb-3"><div class="card-body p-4 d-flex flex-wrap justify-content-between align-items-center gap-3"><div><span class="badge bg-light text-primary mb-2"><?= sanitize($ujian['jenis_ujian']) ?></span><h1 class="h4 fw-bold mb-1"><?= sanitize($ujian['nama_ujian']) ?></h1><p class="mb-0 opacity-75"><?= sanitize($ujian['nama_mapel'].' · '.$ujian['nama_kelas']) ?></p></div><div class="d-flex gap-2 result-metrics"><div class="result-metric"><strong><?= count($peserta) ?></strong><small>Peserta</small></div><div class="result-metric"><strong><?= $selesai ?></strong><small>Selesai</small></div><div class="result-metric"><strong><?= $berlangsung ?></strong><small>Berlangsung</small></div></div></div></section>
<?php if($detail): ?><section class="card result-card mb-3"><div class="card-body p-3 p-md-4"><div class="d-flex flex-wrap justify-content-between align-items-center gap-2 mb-3"><div><a class="small text-decoration-none" href="?ujian_id=<?= $ujianId ?>"><i class="fa-solid fa-arrow-left me-1"></i>Kembali ke peserta</a><h2 class="h5 fw-bold mt-2 mb-1"><?= sanitize($detail['nama_lengkap']) ?></h2><small class="text-muted">NISN <?= sanitize($detail['nisn']) ?> · <?= count($jawaban) ?> soal</small></div><span class="badge <?= $detail['status']==='Selesai'?'bg-success':'bg-warning text-dark' ?>"><?= sanitize($detail['status']) ?></span></div>
<?php foreach($jawaban as $i=>$j): $kosong=$j['tipe_soal']==='PG'?$j['jawaban_pg']===null:trim((string)$j['jawaban_esai'])==='';$benar=$j['tipe_soal']==='PG'&&!$kosong&&(int)$j['is_benar']===1; ?><article class="answer-card"><div class="d-flex justify-content-between gap-2 mb-2"><span class="badge bg-primary">Soal <?= $i+1 ?> · <?= sanitize($j['tipe_soal']) ?></span><small class="text-muted">Bobot <?= (int)$j['bobot'] ?></small></div><div class="answer-question mb-3"><?= nl2br(sanitize($j['pertanyaan'])) ?></div>
<?php if($j['tipe_soal']==='PG'): ?><div class="answer-box <?= $kosong?'answer-empty':($benar?'answer-correct':'answer-wrong') ?>"><div class="d-flex flex-wrap justify-content-between gap-2"><span>Jawaban siswa: <strong><?= $kosong?'Belum dijawab':sanitize($j['jawaban_pg']) ?></strong></span><span>Kunci: <strong class="text-success"><?= sanitize($j['kunci_jawaban']) ?></strong></span></div><?php if(!$kosong): ?><small class="<?= $benar?'text-success':'text-danger' ?>"><i class="fa-solid <?= $benar?'fa-circle-check':'fa-circle-xmark' ?> me-1"></i><?= $benar?'Jawaban benar':'Jawaban salah' ?></small><?php endif ?></div>
<?php else: ?><div class="answer-box <?= $kosong?'answer-empty':'answer-correct' ?>"><strong class="d-block small text-muted mb-1">Jawaban esai siswa</strong><?= $kosong?'<span class="text-muted">Belum dijawab</span>':nl2br(sanitize($j['jawaban_esai'])) ?></div><?php endif ?></article><?php endforeach ?>
</div></section>
<?php else: ?><section class="card result-card"><div class="card-body p-3 p-md-4"><div class="d-flex flex-wrap justify-content-between align-items-center gap-2 mb-3"><div><h2 class="h6 fw-bold mb-1">Daftar Peserta</h2><small class="text-muted">Klik detail untuk melihat setiap jawaban siswa</small></div><div class="d-flex gap-2"><a class="btn btn-sm btn-success" href="ujian_hasil_export.php?format=excel&amp;ujian_id=<?= $ujianId ?>"><i class="fa-solid fa-file-excel me-1"></i>Excel Kelas</a><a class="btn btn-sm btn-danger" href="ujian_hasil_export.php?format=pdf&amp;ujian_id=<?= $ujianId ?>"><i class="fa-solid fa-file-pdf me-1"></i>PDF Kelas</a></div></div>
<?php if(!$peserta): ?><div class="text-center py-5"><i class="fa-solid fa-inbox fa-2x text-muted mb-2"></i><p class="text-muted mb-0">Belum ada siswa yang memulai ujian.</p></div><?php else: ?>
<div class="table-responsive result-desktop"><table class="table table-hover result-table mb-0"><thead class="table-light"><tr><th>Siswa</th><th>Status</th><th>Jawaban</th><th>Waktu</th><th>Nilai Otomatis</th><th>Aksi</th></tr></thead><tbody><?php foreach($peserta as $p): ?><tr><td><strong><?= sanitize($p['nama_lengkap']) ?></strong><br><small class="text-muted"><?= sanitize($p['nisn']) ?></small></td><td><span class="badge <?= $p['status']==='Selesai'?'bg-success':'bg-warning text-dark' ?>"><?= sanitize($p['status']) ?></span></td><td><?= (int)$p['jumlah_dijawab'] ?> / <?= (int)$p['total_soal'] ?></td><td><small>Mulai: <?= date('d/m/Y H:i',strtotime($p['waktu_mulai'])) ?><br>Selesai: <?= $p['waktu_selesai']?date('d/m/Y H:i',strtotime($p['waktu_selesai'])):'-' ?></small></td><td><span class="badge bg-primary score-badge"><?= number_format($p['nilai_total'],2) ?></span></td><td><div class="d-flex gap-1"><a class="btn btn-sm btn-outline-primary" href="?ujian_id=<?= $ujianId ?>&amp;sesi_id=<?= (int)$p['id'] ?>"><i class="fa-solid fa-eye"></i></a><a title="Excel siswa" class="btn btn-sm btn-outline-success" href="ujian_hasil_export.php?format=excel&amp;ujian_id=<?= $ujianId ?>&amp;siswa_id=<?= (int)$p['siswa_id'] ?>"><i class="fa-solid fa-file-excel"></i></a><a title="PDF siswa" class="btn btn-sm btn-outline-danger" href="ujian_hasil_export.php?format=pdf&amp;ujian_id=<?= $ujianId ?>&amp;siswa_id=<?= (int)$p['siswa_id'] ?>"><i class="fa-solid fa-file-pdf"></i></a></div></td></tr><?php endforeach ?></tbody></table></div>
<div class="participant-mobile"><?php foreach($peserta as $p): ?><article class="participant-item"><div class="d-flex justify-content-between align-items-start gap-2"><div><strong><?= sanitize($p['nama_lengkap']) ?></strong><small class="text-muted d-block">NISN <?= sanitize($p['nisn']) ?></small></div><span class="badge <?= $p['status']==='Selesai'?'bg-success':'bg-warning text-dark' ?>"><?= sanitize($p['status']) ?></span></div><div class="d-flex justify-content-between align-items-end mt-3"><div><small class="text-muted d-block">Jawaban <?= (int)$p['jumlah_dijawab'] ?>/<?= (int)$p['total_soal'] ?></small><strong class="text-primary">Nilai <?= number_format($p['nilai_total'],2) ?></strong></div><div class="d-flex gap-1"><a class="btn btn-sm btn-outline-primary" href="?ujian_id=<?= $ujianId ?>&amp;sesi_id=<?= (int)$p['id'] ?>"><i class="fa-solid fa-eye"></i></a><a class="btn btn-sm btn-outline-success" href="ujian_hasil_export.php?format=excel&amp;ujian_id=<?= $ujianId ?>&amp;siswa_id=<?= (int)$p['siswa_id'] ?>"><i class="fa-solid fa-file-excel"></i></a><a class="btn btn-sm btn-outline-danger" href="ujian_hasil_export.php?format=pdf&amp;ujian_id=<?= $ujianId ?>&amp;siswa_id=<?= (int)$p['siswa_id'] ?>"><i class="fa-solid fa-file-pdf"></i></a></div></div></article><?php endforeach ?></div>
<?php endif ?></div></section><?php endif ?>
